const Table = (props) => {


    const products = props.data.products;
    console.log(JSON.stringify(props))

    return (
        <div>
            <li>
                {products.map((product) => (
                    <ul>{product.title} {product.asin} {product.price.current_price} {product.reviews.rating} </ul>
                ))}
            </li>
        </div>
    );
}

export default Table;
